module ripple_carry_adder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] Sum,
    output Cout
);
    wire [3:0] overflow;

    // Full Adder for bit 0
    assign {overflow[0], Sum[0]} = A[0] + B[0] + Cin;
    // Full Adder for bit 1
    assign {overflow[1], Sum[1]} = A[1] + B[1] + overflow[0];
    // Full Adder for bit 2
    assign {overflow[2], Sum[2]} = A[2] + B[2] + overflow[1];
    // Full Adder for bit 3
    assign {Cout, Sum[3]} = A[3] + B[3] + overflow[2];
endmodule
